const express = require('express');
const router = express.Router();
const mongoose = require('mongoose');
const interviewController = require('../controllers/interviewController.cjs');

// NEW: AI-Powered Interview System with Ollama
// Start a new interview session
router.post('/start', interviewController.startInterview);

// Get next question (dynamically generated by AI)
router.post('/next-question', interviewController.getNextQuestion);

// Submit and evaluate an answer
router.post('/submit-answer', interviewController.submitAnswer);

// Get final interview report
router.post('/final-report', interviewController.getFinalReport);

// Get interview transcript
router.get('/transcript/:sessionId', interviewController.getTranscript);

// Get user's interview history
router.get('/user/:userId', interviewController.getUserInterviews);

// LEGACY: Interview Session Schema for compatibility
const InterviewSessionSchema = new mongoose.Schema({
  sessionId: { type: String, required: true, unique: true },
  userId: { type: String, required: true },
  topic: { type: String, required: true },
  difficulty: { type: String, required: true },
  duration: { type: Number, required: true }, // in minutes
  interviewType: { type: String, default: 'face-to-face' },
  
  // Timing data
  startTime: { type: Date, required: true },
  endTime: { type: Date, required: true },
  timeSpent: { type: Number, required: true }, // in seconds
  
  // Questions and answers
  totalQuestions: { type: Number, required: true },
  answeredQuestions: { type: Number, required: true },
  questions: [{
    question: String,
    category: String,
    expectedPoints: [String],
    followUp: String
  }],
  answers: [{
    questionIndex: Number,
    question: String,
    answer: String,
    category: String,
    timestamp: Date,
    timeSpent: Number
  }],
  
  // Assessment data
  assessment: {
    overallScore: Number,
    summary: String,
    categoryScores: {
      technical: Number,
      communication: Number,
      problemSolving: Number,
      experience: Number
    },
    strengths: [String],
    improvements: [String],
    detailedFeedback: String,
    nextSteps: [String],
    interviewReadiness: String
  },
  
  // Metadata
  createdAt: { type: Date, default: Date.now },
  updatedAt: { type: Date, default: Date.now }
});

const InterviewSession = mongoose.model('InterviewSession', InterviewSessionSchema);

// Store interview session
router.post('/store-session', async (req, res) => {
  try {
    console.log('📝 Storing interview session...');
    
    const sessionData = req.body;
    
    // Validate required fields
    if (!sessionData.sessionId || !sessionData.userId || !sessionData.topic) {
      return res.status(400).json({
        success: false,
        error: 'Missing required fields: sessionId, userId, or topic'
      });
    }

    // Ensure all required fields have values with defaults if needed
    const sessionToStore = {
      sessionId: sessionData.sessionId,
      userId: sessionData.userId,
      topic: sessionData.topic,
      difficulty: sessionData.difficulty || 'medium',
      duration: sessionData.duration || 30,
      interviewType: sessionData.interviewType || 'face-to-face',
      startTime: sessionData.startTime || new Date(Date.now() - (sessionData.timeSpent || 0) * 1000),
      endTime: sessionData.endTime || new Date(),
      timeSpent: sessionData.timeSpent || 0,
      totalQuestions: sessionData.totalQuestions || 0,
      answeredQuestions: sessionData.answeredQuestions || 0,
      questions: sessionData.questions || [],
      answers: sessionData.answers || [],
      assessment: sessionData.assessment || {},
      updatedAt: new Date()
    };

    // Use findOneAndUpdate with upsert to avoid duplicate key errors
    // This will update existing session or create new one
    const interviewSession = await InterviewSession.findOneAndUpdate(
      { sessionId: sessionToStore.sessionId },
      sessionToStore,
      { 
        upsert: true, // Create if doesn't exist
        new: true,     // Return the updated document
        setDefaultsOnInsert: true
      }
    );
    
    console.log('✅ Interview session stored successfully');
    console.log(`📊 Session ID: ${sessionToStore.sessionId}`);
    console.log(`👤 User: ${sessionToStore.userId}`);
    console.log(`📚 Topic: ${sessionToStore.topic}`);
    console.log(`⏱️  Duration: ${sessionToStore.timeSpent}s`);
    
    res.json({
      success: true,
      message: 'Interview session stored successfully',
      sessionId: sessionToStore.sessionId,
      data: {
        totalQuestions: sessionToStore.totalQuestions,
        answeredQuestions: sessionToStore.answeredQuestions,
        timeSpent: sessionToStore.timeSpent,
        overallScore: sessionToStore.assessment?.overallScore
      }
    });

  } catch (error) {
    console.error('❌ Error storing interview session:', error);
    console.error('Error name:', error.name);
    console.error('Error message:', error.message);
    console.error('Error stack:', error.stack);
    
    // Check for validation errors
    if (error.name === 'ValidationError') {
      console.error('Validation errors:', JSON.stringify(error.errors, null, 2));
    }
    
    // Check for duplicate key errors
    if (error.code === 11000) {
      console.error('Duplicate key error:', error.keyPattern);
      console.error('Duplicate value:', error.keyValue);
    }
    
    res.status(500).json({
      success: false,
      error: 'Failed to store interview session',
      details: error.message,
      errorType: error.name,
      errorCode: error.code
    });
  }
});

// Get user's interview history
router.get('/history/:userId', async (req, res) => {
  try {
    const { userId } = req.params;
    const { limit = 10, offset = 0 } = req.query;

    const sessions = await InterviewSession.find({ userId })
      .sort({ createdAt: -1 })
      .limit(parseInt(limit))
      .skip(parseInt(offset))
      .select('sessionId topic difficulty duration overallScore createdAt timeSpent answeredQuestions totalQuestions');

    const total = await InterviewSession.countDocuments({ userId });

    res.json({
      success: true,
      sessions,
      pagination: {
        total,
        limit: parseInt(limit),
        offset: parseInt(offset),
        hasMore: (parseInt(offset) + parseInt(limit)) < total
      }
    });

  } catch (error) {
    console.error('❌ Error fetching interview history:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to fetch interview history'
    });
  }
});

// Get specific interview session details
router.get('/session/:sessionId', async (req, res) => {
  try {
    const { sessionId } = req.params;

    const session = await InterviewSession.findOne({ sessionId });

    if (!session) {
      return res.status(404).json({
        success: false,
        error: 'Interview session not found'
      });
    }

    res.json({
      success: true,
      session
    });

  } catch (error) {
    console.error('❌ Error fetching interview session:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to fetch interview session'
    });
  }
});

// Get interview analytics for a user
router.get('/analytics/:userId', async (req, res) => {
  try {
    const { userId } = req.params;

    // Aggregate data
    const analytics = await InterviewSession.aggregate([
      { $match: { userId } },
      {
        $group: {
          _id: null,
          totalInterviews: { $sum: 1 },
          averageScore: { $avg: '$assessment.overallScore' },
          totalTimeSpent: { $sum: '$timeSpent' },
          topicsCount: { $addToSet: '$topic' },
          difficultyBreakdown: {
            $push: {
              difficulty: '$difficulty',
              score: '$assessment.overallScore'
            }
          }
        }
      }
    ]);

    const result = analytics[0] || {
      totalInterviews: 0,
      averageScore: 0,
      totalTimeSpent: 0,
      topicsCount: [],
      difficultyBreakdown: []
    };

    // Calculate difficulty stats
    const difficultyStats = {};
    result.difficultyBreakdown.forEach(item => {
      if (!difficultyStats[item.difficulty]) {
        difficultyStats[item.difficulty] = { count: 0, totalScore: 0 };
      }
      difficultyStats[item.difficulty].count++;
      difficultyStats[item.difficulty].totalScore += item.score || 0;
    });

    Object.keys(difficultyStats).forEach(difficulty => {
      difficultyStats[difficulty].averageScore = 
        difficultyStats[difficulty].totalScore / difficultyStats[difficulty].count;
    });

    res.json({
      success: true,
      analytics: {
        totalInterviews: result.totalInterviews,
        averageScore: Math.round((result.averageScore || 0) * 10) / 10,
        totalTimeSpent: result.totalTimeSpent,
        uniqueTopics: result.topicsCount.length,
        difficultyStats,
        totalHours: Math.round((result.totalTimeSpent / 3600) * 10) / 10
      }
    });

  } catch (error) {
    console.error('❌ Error fetching interview analytics:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to fetch interview analytics'
    });
  }
});

// Update interview session with assessment
router.put('/update-assessment/:sessionId', async (req, res) => {
  try {
    const { sessionId } = req.params;
    const { assessment } = req.body;

    const updatedSession = await InterviewSession.findOneAndUpdate(
      { sessionId },
      { 
        assessment,
        updatedAt: new Date()
      },
      { new: true }
    );

    if (!updatedSession) {
      return res.status(404).json({
        success: false,
        error: 'Interview session not found'
      });
    }

    res.json({
      success: true,
      message: 'Assessment updated successfully',
      session: updatedSession
    });

  } catch (error) {
    console.error('❌ Error updating assessment:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to update assessment'
    });
  }
});

// 🗑️ DELETE - Clear all interview sessions (for database cleanup)
router.delete('/clear-all', async (req, res) => {
  try {
    console.log('🗑️ Clearing all interview sessions from database...');
    
    const result = await InterviewSession.deleteMany({});
    
    console.log(`✅ Deleted ${result.deletedCount} interview sessions`);
    
    res.json({
      success: true,
      message: `Successfully cleared ${result.deletedCount} interview sessions`,
      deletedCount: result.deletedCount
    });

  } catch (error) {
    console.error('❌ Error clearing interview sessions:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to clear interview sessions',
      details: error.message
    });
  }
});

// 🗑️ DELETE - Clear interview sessions for specific user
router.delete('/clear-user/:userId', async (req, res) => {
  try {
    const { userId } = req.params;
    console.log(`🗑️ Clearing all interview sessions for user: ${userId}`);
    
    const result = await InterviewSession.deleteMany({ userId });
    
    console.log(`✅ Deleted ${result.deletedCount} sessions for user ${userId}`);
    
    res.json({
      success: true,
      message: `Successfully cleared ${result.deletedCount} sessions for user`,
      deletedCount: result.deletedCount,
      userId
    });

  } catch (error) {
    console.error('❌ Error clearing user sessions:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to clear user sessions',
      details: error.message
    });
  }
});

// 🗑️ DELETE - Clear old sessions (older than specified days)
router.delete('/clear-old/:days', async (req, res) => {
  try {
    const { days } = req.params;
    const daysAgo = new Date();
    daysAgo.setDate(daysAgo.getDate() - parseInt(days));
    
    console.log(`🗑️ Clearing interview sessions older than ${days} days (before ${daysAgo.toISOString()})`);
    
    const result = await InterviewSession.deleteMany({
      createdAt: { $lt: daysAgo }
    });
    
    console.log(`✅ Deleted ${result.deletedCount} old sessions`);
    
    res.json({
      success: true,
      message: `Successfully cleared ${result.deletedCount} sessions older than ${days} days`,
      deletedCount: result.deletedCount,
      cutoffDate: daysAgo.toISOString()
    });

  } catch (error) {
    console.error('❌ Error clearing old sessions:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to clear old sessions',
      details: error.message
    });
  }
});

module.exports = router;